        for start in range(len(pos) - k + 1):
            left = pos[start]
            right = pos[start + k - 1]
            cur_len = right - left + 1
            if cur_len < best_len:
                best_len = cur_len
                best_sub = s[left:right + 1]
            elif cur_len == best_len:
                cand = s[left:right + 1]
