class Solution:
    def shortestBeautifulSubstring(self, s: str, k: int) -> str:
        n = len(s)
        ones = [0] * (n + 1)
        for i, ch in enumerate(s, 1):
            ones[i] = ones[i - 1] + (ch == '1')

        # Find all minimal-length beautiful substrings:
        min_len = float('inf')
        best = None

        for left in range(n):
            if s[left] == '0':
                continue
            # positions of 1s starting from left
            # Find the (k-th) 1 within window starting at left:
            # We can locate by scanning, since n<=100.
            cnt = 0
            for right in range(left, n):
                if s[right] == '1':
                    cnt += 1
                if cnt == k:
                    L = left
                    R = right
                    cur_len = R - L + 1
                    if cur_len < min_len:
                        min_len = cur_len
                        best = s[L:R + 1]
                    elif cur_len == min_len:
                        cand = s[L:R + 1]
                        if cand < best:
                            best = cand
                    break
                elif cnt > k:
                    break

        return best if best is not None else ""
